import{c as t,W as n,j as s,m as o}from"./chunks/framework.CoQR5MuA.js";const _=JSON.parse('{"title":"赞比亚矿产和矿业法","description":"赞比亚国情资料 — 赞比亚矿产和矿业法","frontmatter":{"title":"赞比亚矿产和矿业法","description":"赞比亚国情资料 — 赞比亚矿产和矿业法"},"headers":[],"relativePath":"mining/zambia/zh/mining-law-notes.md","filePath":"mining/zambia/zh/mining-law-notes.md","lastUpdated":1780319686000}'),r={name:"mining/zambia/zh/mining-law-notes.md"};function g(a,p,i,e,d,c){return n(),s("div",null,[...p[0]||(p[0]=[o('<h1 id="赞比亚矿产和矿业法" tabindex="-1">赞比亚矿产和矿业法 <a class="header-anchor" href="#赞比亚矿产和矿业法" aria-label="Permalink to &quot;赞比亚矿产和矿业法&quot;">​</a></h1><div class="reading-prose"><p><strong>赞比亚政府</strong></p><p><strong>矿产和矿业发展法</strong></p><p><strong>2008年第7号法案</strong></p><p>颁布日期：2008年03月27日</p><p><strong>本法案修订了关于矿物勘探、开采和加工方面的法规；本法案废除和取代了1995年颁布的《矿产和矿业法》；本法案补充了与上述法规、法案相关的、连带的事项。</strong></p><p><strong>2008年4月4日</strong></p><p>本法案被赞比亚国会审议通过。</p><p><strong>第一部分</strong></p><p>序言</p><p><strong>1条</strong></p><p>第(1)款：本法案可作为《矿产和矿物发展法》（2008年版）被引用。</p><p>第(2)款：本法案自2008年4月1日开始生效。</p><p><strong>2条</strong></p><p>第(1)款：在本法案中，除非上下文另有说明，否则：</p><p>“<strong>进入协议</strong>”是指采矿权持有人与采矿权限定地块的所有人或占有人之间，在此地块上为执行矿物勘探、开采或其它由采矿权所赋予的作业的规则而达成的协议；</p><p>“<strong>人工采矿权</strong>”是指根据本法案第五部分规定批准的人工采矿权；</p><p>**“贱金属”**是指普通的或含有化学活性的、或普通的和含有化学活性的非贵重金属，包括：铁、铜、镍、铝、铅、锌、锡、镁、钴、锰、钛、钪、钒和铬；</p><p>**“鸟类禁猎区”**是指根据1998年《赞比亚野生动物法》第144条规定所划定的区域；</p><p>**“地籍单位”**是指由经纬线交叉形成的四边形，边距等于6个六十位进制的秒，一个地籍单位平均覆盖3.34400公顷的地表面积；</p><p>**“中央矿业地籍办公室”**是指根据本法案第145条规定设立的办公室；</p><p>**“公民所有制公司”**是指赞比亚公民至少拥有51%的股份，及拥有重大管理决策权的公司；</p><p>“<strong>税务总长</strong>”是指根据《赞比亚税务局法》被委任的税务总长；</p><p>“<strong>矿业司长</strong>”是指根据本法案第144条规定被委任的司长；</p><p>“<strong>地质测量司司长</strong>”是指根据本法案第144条第(3)款的规定被任命的司长；</p><p>“<strong>矿业安全司司长</strong>”是指根据本法案第144条第(2)款的规定被任命的司长；</p><p>“<strong>能源矿物</strong>”是指地表外层中产生的作为能源原料使用的天然物质，包括：煤、铀，和其它可产生能源的矿物，但不包括石油；</p><p>“<strong>赞比亚环境委员会</strong>”在《环境保护和污染控制法》中有其定义；</p><p>“<strong>环境影响研究</strong>”在1997年版的《环境保护和污染控制规定》中（环境影响评估）有其定义；</p><p>“<strong>环境管理方案</strong>”是指赞比亚环境委员会根据《环境保护和污染控制法》的规定批准的方案；</p><p>“<strong>游乐管理区</strong>”是指根据1998年《赞比亚野生动物法》第26条规定而划定的区域；</p><p>“<strong>宝石销售证书</strong>”是指根据本法案第七部分批准的宝石销售证书；</p><p>“<strong>宝石</strong>”是指紫水晶、海蓝宝石、绿柱石、刚玉、钻石、祖母绿、石榴石、红宝石、蓝宝石、黄玉、电气石和其它非金属矿物质，即用于珠宝制作的、经矿业部长以法令形式宣告为某种宝石的物质；</p><p>“<strong>持有人</strong>”是指根据本法案被注册为具有采矿权的人；</p><p>“<strong>工业矿物</strong>”是指除了宝石、贱金属、能源矿物、或以自然形态或加工后（物理或化学变化）形态使用的贵金属之外的岩石或矿物，及包含但不受限于以下物质：重晶石、白云石、长石、萤石、石墨、石膏、用作助熔剂的铁矿石、蓝晶石、石灰岩、千枚岩、菱镁矿、云母、硝酸盐、磷酸盐、叶蜡石、盐、砂子、粘土、滑石、红土、砂砾和其它用作此用途的岩石（如果矿业部长通过法令将任何其它的矿物归类为一种工业矿物）；</p><p>“<strong>大规模宝石许可证</strong>”是指根据本法案第三部分的规定批准的大规模宝石许可证，其持有人可进行相关的宝石探矿和开采工作；</p><p>“<strong>大规模采矿许可证</strong>”是指根据本法案第三部分的规定批准的大规模采矿许可证；</p><p>“<strong>地方森林</strong>”是指根据《森林法》第17条的规定划定的区域；</p><p>“<strong>地方办事处</strong>”是指为任何地方区域设立的政府部门的办事处；</p><p>“<strong>矿山</strong>”是指在其中或其上进行与采矿有关的任何作业的场地、露天坑、竖井、开拓巷道、阶段平巷或其它的采掘空间，以及任何平巷、沟槽、通道、矿脉、倾斜矿脉、缓倾斜矿脉、盐池或工作面，包括无论是在地上或地下，用于与任何这样的作业相联系的或为任何矿物的提取、处理或分选的或为矿石加工目的之所有的建筑物、房屋、设施和装备。</p><p>“<strong>矿物</strong>”是指在地表内或地表上、或在水中或水下由于地质演变自然生成的，及任何由储藏、储备的残留物生成的矿物，但不包括：</p><p>除了取自于土地中的或任何能从其中提取矿物的水资源之外的水利资源；以及</p><p>石油</p><p>“<strong>矿物加工</strong>”是指从矿石中分离、提取有价值的矿物，提取步骤包括：轧、磨、分级、筛选、分类、冲洗、泡沫浮选、重力选矿、静电分离、磁选、淋滤、冶炼、精炼、煅烧、气化或任何其它相关的加工步骤；</p><p>“<strong>矿物加工许可证</strong>”是指根据本法案第六部分的规定批准的矿物加工许可证；</p><p>“<strong>矿物费用</strong>”是指矿物提取时产生的费用；</p><p>“<strong>采矿</strong>”是指从土地上或地表以下，为了获取各种无论是固态、液态、或气态的矿物所进行的原料开采，包括任何必需的直接的、间接的或附带的作业；</p><p>“<strong>矿业咨询委员会</strong>”是指根据本法案第150条的规定组建成立的矿业咨询委员会；</p><p>“<strong>采矿区域</strong>”是指本法案批准的采矿许可证或特许证所圈地的区域；</p><p>“<strong>矿业地籍办公室</strong>”是指在卢萨卡组建成立的中央行政办公室，负责采矿权和非采矿权的受理及管理；</p><p>“<strong>采矿作业</strong>”是指根据本法案第6条规定进行的任何采矿权所赋予的作业，但不包含在探矿特许、探矿许可证或矿物加工许可证下赋予的作业；</p><p>“<strong>采矿设施</strong>”是指用于采矿的、不论是否固定在土地上的任何建筑物、厂房、机械、设备、工具或其它财产，但不包括任何用于构造或支护任何竖井、开拓巷道、平巷、台阶、水槽、水坝或其它内容的木材或其它材料；</p><p>“<strong>采矿权</strong>”是指根据本法案第6条第(1)款规定批准的权利；</p><p>“<strong>国家森林</strong>”是指根据《森林法》第8条规定划定的区域；</p><p>“<strong>国家公园</strong>”是指根据《赞比亚野生动物法》第10条规定划定的区域；</p><p>“<strong>非采矿权</strong>”是指根据本法案规定批准的矿物加工许可证、或宝石销售许可证；</p><p>“<strong>矿石</strong>”是指一种天然骨料，可从其中的某些部分提炼出一种或多种有价值的矿物元素；</p><p>“<strong>矿体</strong>”是指连续的、集中的矿石群；</p><p>“<strong>石油</strong>”在《石油（勘探和开采）法》中有其定义，但不包括煤或油页岩；</p><p>“<strong>初步勘测权</strong>”是由地质测量司司长根据本法案第5条第(2)款的规定批准的权利；</p><p>“<strong>个人</strong>”包括合作、合伙关系的自然人；</p><p><strong>“勘探</strong>”是指以任何方式开展的任何矿物的搜寻，并可在必要时取走矿物勘探样品以测试任何土地上的含矿质量。</p><p>“<strong>探矿区域</strong>”是指探矿许可证或探矿特许的权限所圈定的区域；</p><p>“<strong>探矿许可证</strong>”是指根据本法案第三部分规定批准的探矿许可证；</p><p>“<strong>探矿工作</strong>”是指在探矿作业的过程中进行的工作；</p><p>“<strong>探矿特许</strong>”是指根据本法案第四部分规定批准的探矿特许；</p><p>“<strong>放射性矿物</strong>”是指在1%的铀、或钍、或任何相关的铀钍综合物中至少含有其二十分之一重量的矿物，包含但不受限于；</p><p>独居石矿砂和其它的含钍矿石；以及</p><p>钾钒铀矿、沥青铀矿和其它的含铀矿石</p><p>“<strong>地方矿业地籍办公室</strong>”是指在卢萨卡之外的赞比亚其它地方行政区域，设立的矿业地籍办公室，负责地方区划的采矿权和非采矿权涉及地块的申请受理；</p><p>“<strong>注册登记</strong>”是指根据本法案第112条规定批准的、有效的注册登记；</p><p>“<strong>使用费</strong>”是指根据本法案规定而交纳的费用；</p><p>“<strong>小规模宝石许可证</strong>”是指根据本法案第四部分规定批准的小规模宝石许可证；以及</p><p>“<strong>小规模采矿许可证</strong>”是指根据本法案第四部分规定批准的小规模采矿许可证。</p><p>第(2)款：在本法案的任何规定中，相关的授权官员是指根据本法案第144条规定被委任的，其官员有权行使和履行其授权中规定的权力和职责。</p><p>第(3)款：在本法案中涉及到的采矿权覆盖土地，是指采矿权已获准并在其有效期内所圈定的区域。</p><p><strong>3条</strong></p><p>第(1)款：对赞比亚境内的矿物所拥有的搜寻、开采和处理权限，归赞比亚总统代表国家所有。</p><p>第(2)款：尽管任何人均可以拥有土地中或土地上的任何权利、资格和利益，但一旦在该土地的其中、其上或其下发现了矿物，本条的规定就是有效的。</p><p><strong>第二部分</strong></p><p>采矿权</p><p><strong>4条</strong></p><p>根据本法案的其它规定，探矿权、采矿权、矿物加工权，均需按本法案要求来获得和持有。</p><p><strong>5条</strong></p><p>第(1)款：未取得按本法案规定批准的采矿权或矿物加工许可证所赋予的权力，任何组织或个人不得进行探矿、采矿或矿物加工作业。</p><p>第(2)款：地质测量司司长可以附加某些其有权附加的条款（包括有工作和费用），书面批准以下权利（期限不得超过90天）：进入任何未获采矿权的区域、或进行航测（通过地球物理学、地球化学和摄影地质学调查或地表地质学研究，以便使勘探工作可以对矿物进行定位）。</p><p>第(3)款：根据本条第(2)款规定由地质测量司司长批准的权利，其权利持有人不得在已递交采矿权申请的区域内行使其权利。</p><p>第(4)款：任何违反本条第(1)款规定的组织或个人，其违反事实一经确认，即构成违法，需承担相关的法律责任：</p><p>个人情形，需交纳不超过K1,000.000.00的罚金，或接受不超过10年的监禁，或两罪并罚；或者</p><p>法人或非法人机构情形，需交纳K5,000.000.00的罚金。</p><p><strong>6条</strong></p><p>第(1)款：按照本法案规定可批准颁发的采矿权如下：</p><p>探矿许可证；</p><p>大规模采矿许可证；</p><p>大规模宝石许可证；</p><p>探矿特许；</p><p>小规模采矿许可证；</p><p>小规模宝石许可证；以及</p><p>人工采矿权。</p><p>第(2)款：按照本法案规定可批准颁发的非采矿权证如下：</p><p>矿物加工许可证；以及</p><p>宝石销售许可证。</p><p><strong>7条</strong></p><p>第(1)款：不符合本法案规定的任何组织或个人不具备持有采矿权或非采矿权的资格。</p><p>第(2)款：下列组织或个人不具备持有采矿权或非采矿权的资格：</p><p>个人情形：</p><p>不满18岁；</p><p>已是或即将成为未清偿债务的破产者、已经宣判或根据任何法律条文宣告破产的破产者、由其债权人提出的任何协议和方案的参与者、为了救助破产者或破产的债务人所执行的任何法律程序的受益者；或</p><p>因欺诈或欺瞒、或任何本法案、或赞比亚法律或他国法律规定的违法行为，而被定罪判处监禁（未同时被罚款或同时被处以超过50,000的罚金）的前十年监禁期限内；或</p><p>法人情形：</p><p>处于资产清算阶段、或公司重组方案中除了资产清算外其它事宜筹划阶段、或与其它公司合并的阶段；</p><p>除非该公司已按《公司法》的规定组建成立；</p><p>尚未在赞比亚设立办公室；或者</p><p>本款(a)段(ii)或(iii)节规定下的任何个人被取消董事或股东资格。</p><p>第(3)款：探矿特许、小规模采矿许可证、小规模宝石许可证和人工采矿权，不得被授予任何非赞比亚公民或非赞比亚公民所有制公司。</p><p>第(4)款：工业矿物的采矿权只能被授予赞比亚公民或赞比亚公民所有制公司。</p><p>第(5)款：任何拟授予不具备持证资格的组织或个人的文件或拟开展的事务均是无效的。</p><p>第(6)款：本法案中“赞比亚公民”指的是：</p><p>个人情形，即该个人是拥有赞比亚国籍的公民；及</p><p>合作人情形，即该合作人均由拥有赞比亚国籍的公民构成。</p><p><strong>8条</strong></p><p>采矿权、或矿物加工许可证、及其赋予的各项权力，均应遵从本法案、及其权证颁布时所附加的各项条款规定，及在采矿权、或矿物加工许可证有效期限内遵照本法案要求对其权证内的条款进行修订后的各项规定。</p><p><strong>9条</strong></p><p>根据本法案规定，同一个地块上的采矿权申请人超过一个时，地质测量司司长可按照申请收讫的先后顺序，对采矿权申请进行批复。</p><p><strong>10条</strong></p><p>第(1)款：拟申请的采矿权涉及区域已被另一个采矿权所圈定，则采矿权申请人可向另一个采矿权持有人申请划区许可，且该许可不应被无理由拒绝。</p><p>第(2)款：采矿权申请人根据本条第(1)款规定向采矿权持有人提交的申请满足下列情形时，采矿权持有人应在90天内同意采矿权申请人的划区许可：</p><p>采矿权申请人所申请勘探、开采的矿物或金属与采矿权持有人的权证上指明的矿物或金属不一致；</p><p>采矿权申请人所申请勘探、开采的矿物或金属的地理位置，与采矿权持有人已获准的工作规划书中所指示的矿体地理位置不一致；</p><p>采矿权申请人所申请勘探、开采的矿物或金属的地质方位，与采矿权持有人已获准的工作规划书中所指示的厂房和基础设施的地质方位不一致；或者</p><p>采矿权申请人所申请勘探、开采的矿物属于工业矿物，且采矿权持有人所享有的权限在本法案下不适用。</p><p>第(3)款：采矿权持有人拒绝采矿权申请人的划区申请，采矿权申请人可将拒绝结果转至矿业咨询委员会，使其能根据本条第(2)款(a)到(d)段的规定做出裁决。</p><p><strong>11条</strong></p><p>在签发采矿权或矿物加工许可证之前，矿业司长或地质测量司司长可按照本法案规定，要求对拟签发权证所涉及的地块进行适当的勘测。</p><p><strong>12条</strong></p><p>第(1)款：根据本法案的其它规定，矿业部长可在赞比亚普遍发行的报纸上发布招标通告，邀请投标人对指定地块或矿物资源的采矿权进行投标。</p><p>第(2)款：按照本条第(1)款规定发布的招标通告应包含：</p><p>拟招标地块的描述；</p><p>投标的程序和规则；</p><p>投标的有效期限。</p><p>第(3)款：矿业部长应在本条第(2)款第(c)段指定的投标截止日期前5天内，通知所有投标人将其按照本条规定制作的标书递交到矿业咨询委员会进行评标。</p><p>第(4)款：矿业咨询委员会在评标时应考虑：</p><p>投标人的投资和财务方案；</p><p>投标人的环境管理方案；</p><p>在投标人已持有采矿权的情形下，该持有人是否遵守本法案及采矿权的规定；以及</p><p>为推行本法案而引申的任何其它相关因素。</p><p>第(5)款：标书符合本法案要求时，矿业咨询委员会应建议矿业部长按照本法案规定将采矿权授予投标人。</p><p>第(6)款：矿业部长应考虑矿业咨询委员会的举荐，将采矿权许可证授予给最优投标方案的投标人。</p><p><strong>13条</strong></p><p>第(1)款：按本法案规定签发的采矿权或矿物加工许可证持有人，应在执行权证内规定的工作时，及在采购、基建和安装矿业设施时，尽可能最大程度地优先考虑选用：</p><p>赞比亚所产的物资和产品；</p><p>由赞比亚公民或赞比亚公民所有制公司所拥有的、在赞比亚境内的服务机构。</p><p>第(2)款：采矿权或矿物加工许可证持有人在进行矿业工作的各个阶段，应尽可能最大程度优先考虑雇佣赞比亚公民。</p><p>第(3)款：采矿权或矿物加工许可证持有人在进行矿业工作时，应与矿业部长协商执行培训计划，以利于雇员提高矿业技能。</p><p><strong>第三部分</strong></p><p>大规模采矿作业</p><p>第一章 探矿许可证</p><p><strong>14条</strong></p><p>第(1)款：探矿许可证申请应按规定的格式填写并递交至地质测量司司长处，并交纳规定的申请费用。</p><p>第(2)款：依据本条第(1)款规定编制的申请，应包含如下要素：</p><p>使用地理坐标对申请的地块进行详细的描述，此地块不应在面积上大于29,940个地籍单位，地籍单位描述须完整、不被分割；</p><p>申请人所勘探的矿物说明；</p><p>一份申请人的环境管理方案，包括：防止污染预案、尾矿处理方案、土地及水利资源保护及再生方案，及能够消除或最小化探矿作业对环境所造成的负面影响的方案；</p><p>一份探矿计划书和一份针对于探矿计划书而立的投资承诺书；</p><p>申请人针对雇佣及培训赞比亚公民的方案；</p><p>申请人针对当地商业发展的规划；</p><p>一份依据“所得税法”出具的完税证明；以及</p><p>其它的按照矿业部长或相关法令要求完备的材料。</p><p>第(3)款：任何个人、公司或公司的相关组织，其持有的探矿许可证所覆盖的累积探矿面积，不得大于149,700个地籍单位。</p><p><strong>15条</strong></p><p>第(1)款：地质测量司司长在审核申请人按照本法第14条规定制作提交的探矿许可证申请时，应考虑如下要素：</p><p>申请人具有或有能力具有充足的资金来源、雄厚的技术实力和丰富的矿业经验，使其能够有效地展开探矿工作；</p><p>申请人具有详尽的探矿方案及适当的环境保护方案；</p><p>若申请人所申请的探矿区域位于国家公园、动物乐园、国家森林、地区森林、鸟类禁猎区之内，或位于本法第127条第（1）款所限定的区域内，则申请人必须要获准必要的进场同意函；</p><p>拟申请的探矿区域与现有的探矿区域、采矿区域或划批区域相互之间不雷同或重叠；以及</p><p>若申请人曾持有过探矿许可证，且未曾违反其持有权证或本法案的任何规定。</p><p>第(2)款：若地质测量司司长认为有必要进行审核，以评定申请人是否满足本条第（1）款的规定，则司长可执行相关的调查与咨询工作。</p><p>第(3)款：地质测量司司长针对下列情形，将不予发证给申请人：</p><p>申请人因本法案第7条规定，而不具备持有探矿许可证的资格；</p><p>申请人已持有另外的采矿权许可证，但违反了其所持权证或本法案的任何规定；</p><p>申请人所申请的地块或其中的一部分地块，处于：</p><p>另外的采矿权许可证限定范围内，且持证人尚未同意申请人所申请行使的权限；或者</p><p>地质测量司司长规划中或规划内并已授权可以通过实际工作和费用的方式来进行初步勘测的区域，除非申请人持有该授权；或者</p><p>申请人所申请的地块覆盖或包含了申请人之前的另外的申请人所申请的地块。</p><p>第(4)款：探矿许可证申请因本条第（3）款规定而被地质测量司司长拒绝，司长应将受理结果通知申请人并阐述其拒绝理由。</p><p>第(5)款：所申请的新的探矿许可证涉及的探矿区域已被旧的（他人的）探矿许可证圈定，且旧的持证人持证时间满7年，则地质测量司司长在旧的探矿许可证到期后的2个月之前，不应将新的探矿许可证授予申请人。</p><p><strong>16条</strong></p><p>第(1)款：根据本法案第14条规定编制递交的探矿许可证申请符合本法案的要求时，地质测量司司长应在收到该申请后的60天内，将探矿许可证授予申请人。</p><p>第(2)款：探矿许可证中应含有如下内容：</p><p>注明探矿工作的开始日期和本权证的各项条款；</p><p>注明本权证限定勘探的矿物；以及</p><p>针对探矿区域的描述与项目计划。</p><p>第(3)款：由地质测量司司长审核通过的探矿规划书应附在探矿许可证上，且应被视为探矿许可证的部分条款。</p><p>第(4)款：在敲定探矿许可证拟注明的探矿工作开始日期时，按照探矿许可证申请人的要求，地质测量司司长应考虑到，自签发探矿许可证之日起，其后不超过6个月的任何期限内，均应被视为申请人为着手探矿工作而进行的项目准备阶段。</p><p><strong>17条</strong></p><p>第(1)款：根据本法案的其它规定，探矿许可证的法定有效期限为2年。</p><p>第(2)款：探矿许可证到期时，可申请延期2年，但总的有效年限不能超过7年。</p><p><strong>18条</strong></p><p>持证人根据探矿许可证所赋予的权利，可在其探矿区域内对宝石矿之外的探矿许可证中限定的其它矿物进行勘探或进行所有与探矿作业相关的、有必要的其它活动。</p><p><strong>19条</strong></p><p>第(1)款：探矿许可证持有人应：</p><p>自签发探矿许可证之日起，在90天或由地质测量司司长批准的更长期限内，开始具体的探矿工作；</p><p>一经探明任何可能具备商业价值的矿床，应在探明后的30天内将结果通知到地质测量司司长；</p><p>保证探矿项目实施经费不少于探矿许可证条款中描述的或要求的预期经费；</p><p>按探矿规划书要求开展探矿工作；</p><p>在探矿许可证中涉及的矿物被探明后的30内将探明结果报告给地质测量司司长；</p><p>按地质测量司司长指定的方式将探矿工作过程中开凿的地点进行回填或以其它方式进行安全处理；</p><p>在探矿作业结束后，对探矿涉及的钻孔、其它矿物样本、洞穴和其它水利资源，按地质测量司司长规定的方式，不通过赔偿手段而进行永久性的原貌保留或者安全防护，并交与当地政府处理；</p><p>在探矿许可证到期或结束前的60天内，按地质测量司司长指定的方式（地质测量司司长另有其它规定除外），撤走任何的营地、临时建筑物或竖立、安装的机械设备，及修复或修缮由于撤离活动造成的地表损害；</p><p>根据矿业部长指定的方式，对环保事宜进行记录和保存；</p><p>按照探矿许可证的规定和地质测量司司长的批文，保障探矿费用与探矿规划书中的拟定费用一致，即不少于探矿许可证中规定的金额；以及</p><p>至少向地质测量司司长提交探矿季报，且季报中应含有探矿许可证和本法案规定要提供的内容。</p><p>第(2)款：探矿许可证持有人应在其办公场所里，对如下的探矿工作进行详尽、准确的记录：</p><p>钻孔；</p><p>穿透的岩层及该岩层的详细记录；</p><p>探明的矿物；</p><p>任何地震勘测或地球化学、地球物理及远程感应数据分析的结果；</p><p>根据本法案第22条规定从矿区带走的矿物样本的任何分析和鉴别结果；</p><p>对本款(a)到(e)段所列记录的地质学分析说明；</p><p>雇员数量；</p><p>任何其它的探矿作业；</p><p>探矿费用；以及</p><p>矿业部长根据法令而规定的其它事宜；</p><p>且每隔3个月，将如上工作记录的电子版和纸介版提交给矿业司长、地质测量司司长和矿业安全司司长。</p><p>第(3)款：探矿许可证持有人如果：</p><p>未根据本条第(2)款规定对任何需要保存的工作记录和材料进行保存；</p><p>未根据本条第(2)款规定将任何需要提交给矿业司长、地质测量司司长和矿业安全司司长的工作记录或矿物样本进行提交；或者</p><p>提交了任何不真实的或具有误导性质的工作记录或材料；</p><p>如上情形一经证实，即构成违规，需承担相应的责任，即交纳不超过K200,000.00的罚金或接受不超过2年的监禁或两罪并罚。</p><p><strong>20 条</strong></p><p>第(1)款：探矿许可证持有人若需要对探矿规划书中的内容做任何修改，则应按照指定的格式将修改申请递交给地质测量司司长。</p><p>第(2)款：地质测量司司长收到探矿许可证持有人依据本条第（1）款规定递交的修改申请后，有权：</p><p>批准申请，且附加或不附加其职权范围允许修改的条款；或者</p><p>拒绝申请并阐明理由。</p><p><strong>21条</strong></p><p>第(1)款：按照本条第(2)、(3)款规定，探矿许可证或其任何相关权益、或探矿许可证持有人的任何控股权益，均可被转让给任何组织或个人。</p><p>第(2)款：探矿许可证持有人拟转让其权证或相关权益，应至少提前30天，将其转让意向传达给矿业部长。</p><p>第(3)款：探矿许可证持有人在向矿业部长传达其与本条第(2)款规定相关的转让意向时，应同时将受让人的详细资料提交给矿业部长，按本法案第14条规定，受让人在申请探矿许可证时该资料需要被提供。</p><p>第(4)款：矿业部长经核实认定受让人符合本法案各条款要求，具备持有探矿许可证的资格，则矿业部长应批准探矿许可证或其相关权益允许转让，并通知涉及转让事宜的组织或个人。</p><p>第(5)款：转让达成后，探矿许可证受让人应在权证的剩余有效期限内，承接起原属于转让人应行使和履行的各项权利和义务。</p><p>第(6)款：任何违反本条规定的探矿许可证转让行为均是无效的。</p><p><strong>22条</strong></p><p>第(1)款：除矿物分析或实验用途之外，未经取得地质测量司司长的书面批准，探矿许可证持有人不得从探矿区域取走任何矿物样本，在取得书面批准后，应按批准中规定的方式带走矿物样本。</p><p>第(2)款：从探矿区域带走的用于分析和实验用途的矿物样本，其具体数量由矿业部长通过法令形式决定。</p><p><strong>23条</strong></p><p>第(1)款：探矿许可证持有人在行使其权证赋予的权力的过程中，探明了权证限定之外的矿物，则该持有人应向地质测量司司长申请对原探矿许可证进行修正，使其能够涵盖已探明的矿物。</p><p>第(2)款：根据本条第(1)款规定提交的探矿许可证修改申请，应：</p><p>注明所探明的矿物；</p><p>详细描述探明矿物的地点和地理环境；以及</p><p>在原探矿规划书中补充一项针对该探明矿物的探矿计划。</p><p>第(3)款：根据本条第(4)款规定及申请人的法纪表现，地质测量司司长应批准探矿许可证持有人将其探明的矿物纳入到修正后的权证限定范围之内。</p><p>第(4)款：若本条第(1)款规定涉及的探明矿物是宝石，则探矿许可证持有人应按照本法案第36条规定，申请大规模宝石许可证。</p><p>第(5)款：探矿许可证持有人一经探出石油，应在探明后的24小时内，将结果上报给矿业部长。</p><p><strong>24条</strong></p><p>第(1)款：探矿许可证到期前，持证人应提前3个月，按指定的格式向地质测量司司长申请权证更新，并交纳规定的申请费用。</p><p>第(2)款：探矿许可证持有人在符合下列情形时，地质测量司司长应将其权证进行更新，更新后的有效期限不得超过2年：</p><p>没有违反其权证或本法案的任何规定；</p><p>在权证更新期间，着手制定、完善新的探矿工作书；以及</p><p>同意首次权证更新后的探矿区域比原区域缩减一半，及第二次权证更新后的探矿区域缩减到原区域的四分之一。</p><p>第(3)款：若探矿许可证持有人对任何矿物所进行的“资源再生勘探及其商业价值”的可行性研究，有必要继续进行直至完成，则地质测量司司长可在探矿许可证更新2年的基础上额外续期，但时间不能超过1年。</p><p>第二章 大规模采矿许可证</p><p><strong>25条</strong></p><p>第(1)款：探矿许可证持有人，有资格申请大规模采矿许可证，使其对探矿区域内的矿物进行开采。</p><p>第(2)款：大规模采矿许可证申请应按指定的格式填写且提交至矿业司长，并交纳规定的申请费用。</p><p>第(3)款：大规模采矿许可证申请应包括：</p><p>一份说明所申请的许可证期限的文件；</p><p>一份说明许可证限定开采的矿物的文件；</p><p>一份全面的文件，用以说明所申请的采矿区域内其矿物细目，包括探明的、预期的或预想中的矿石、矿物，及其各自的开采条件；</p><p>一份采矿规划书，内容包括投资额度预期、矿石及其它矿产品预计回收率、以及针对回收的矿石及矿产品所制定的计划处理方案；</p><p>一份申请人的环境管理方案，内容包括：防止污染预案、尾矿处理方案、土地及水利资源保护及再生方案，以及其它能够防止或最小化采矿计划对环境所产生的负面影响的方案；</p><p>一份预期的基建要求说明；</p><p>一份申请人针对雇佣及培训赞比亚公民所做出的方案；</p><p>一份申请人对当地商业发展所做出的计划，具体方式如下：</p><p>允许赞比亚企业参与申请人的采购、供应项目；</p><p>使用赞比亚企业提供的产品来取代进口产品，并尽可能将修理和维护工作交给当地的公司来做；</p><p>推动赞比亚企业与外资供应商、承包商的合作；以及</p><p>为赞比亚企业提供培训以提高他们在参与承包及供应项目时的质量标准；</p><p>一份使用地理坐标对申请地块进行详细描述的文件，此地块不应在面积上大于7,485个地籍单位，且地籍单位须完整并不被分割；</p><p>一份依据“所得税法”出具的完税证明；</p><p>一份按照矿业部长可能要求的格式和内容而准备的采矿区域计划；以及</p><p>其它地质测量司司长可能要求提供的用于采矿许可证申请评定的材料。</p><p>第(4)款：大规模采矿许可证申请若涉及到辐射性矿物，则需在申请中附加如下材料：</p><p>一份矿山、矿物加工设施和处理场地的计划与说明；</p><p>一份根据《电离辐射保护法》规定签发的相关许可证的拷贝件；</p><p>一份方案书，针对居住在矿山或矿物加工设施附近的居民，向其阐述辐射性矿物开采与加工将会对居住环境、人身健康与安全造成的预期影响的性质与特点；</p><p>一份方案书，用来协助采矿区域外围的有关当局如何计划和准备去限制辐射性物质意外排放的负面影响；</p><p>一份人工防护设备采购、使用和维护的计划书；</p><p>一份针对工人的辐射安全培训方案书；</p><p>一份通风和防尘方法、及相关设备的计划书；</p><p>一份安全方案书，包括任何辐射性矿物的仓储、运输安全，及警惕在矿山或矿物加工设施上的蓄意破坏行为；</p><p>一份辐射性矿物仓储、运输和营销方案说明；以及</p><p>其它矿业司长可能根据法令指定的要求。</p><p>第(5)款：大规模采矿许可证申请人应委托专业机构根据其预定的采矿作业制定一份环境影响报告，且经赞比亚环境委员会审核通过后，将此报告提交给矿业司长。</p><p><strong>26条</strong></p><p>第(1)款：在审批按照本法案第25条规定制作提交的申请时，矿业司长应考虑如下要素：</p><p>矿区是否有足够的矿物储量值得去进行商业性开采；</p><p>所申请的矿区面积不超过申请人预定计划开采所要求的合理面积；</p><p>根据公认的高效采矿标准，申请人的采矿规划书应确保有效、有益地利用其申请矿区的矿物资源；</p><p>申请人的环境管理方案需符合赞比亚针对受采矿工作影响的环境管理国家标准制定的规范；</p><p>申请人是否有或是否获得充足的资金来源、雄厚的技术实力和丰富的采矿经验以保障能高效地进行采矿工作；</p><p>如果采矿区域位于国家公园、游乐园管理区、国家森林或地区森林、或鸟类禁猎区、或本法案第127条限定下的地块内，申请人在进入采矿区域之前是否已获得必要的进场批准；</p><p>根据申请人所申请的采矿项目的大小和类型，申请人针对赞比亚公民的雇佣和培训方案是否符合项目需求；以及</p><p>申请人没有违反探矿许可证或本法案的任何规定。</p><p>第(2)款：矿业司长如果认为有必要去评估申请人的申请条件是否满足本条所规定的要求，则矿业司长可能会对申请人的资质进行调查或咨询。</p><p>第(3)款：采矿许可证申请不符合本法案规定的要求时，矿业司长应拒绝申请，并向申请人阐述理由。</p><p><strong>27条</strong></p><p>第(1)款：根据本法案的其它规定，按照本法案第25条规定编制提交的申请满足本法案的要求时，矿业司长在收到该申请后的60天内，应将采矿许可证（采矿区域取自于探矿区域的一部分）签发给申请人，并有权附加条款。</p><p>第(2)款：大规模采矿许可证应：</p><p>注明其签发日期、有效期限和权限条款；以及</p><p>包含一份权证所圈定的采矿区域的说明和计划书。</p><p>第(3)款：大规模采矿许可证应附有如下材料：</p><p>由矿业司长审核通过的采矿规划书；</p><p>申请人的环境管理方案书；</p><p>申请人关于雇佣和培训赞比亚公民的方案书；</p><p>申请人关于促进当地商业发展的计划书；</p><p>申请人的投资额度预期方案书；</p><p>以上附件均构成采矿许可证的附属条款。</p><p><strong>28条</strong></p><p>除提前吊销外，所签发的采矿许可证有效期限不得超过25年。</p><p><strong>29条</strong></p><p>第(1)款：大规模采矿许可证持有人可根据其权证所赋予的权利，在采矿区域内对除了宝石之外的权证中限定的矿物进行开采或其它有必要的、合理的、相关的矿业活动。</p><p>第(2)款：除了本条第(1)款的一般规定外，大规模采矿许可证持有人还有权：</p><p>进入采矿区域，进行以采矿为目的的所有合理的地表或地下矿业工作；</p><p>装配必要的设备、工厂和建筑物，用于在采矿过程中所探明矿物的开采、运输、加工或处理；</p><p>对任何探明的矿物进行处理；</p><p>在采矿区域内对除宝石之外的矿物进行勘探；以及</p><p>根据环境管理方案堆积或倾倒任何废矿或废品。</p><p><strong>30条</strong></p><p>第(1)款：大规模采矿许可证持有人应履行如下义务：</p><p>根据采矿规划书和环境管理方案规定，积极开发采矿区域，进行采矿工作；</p><p>进行所有合理的地表或地下矿业工作，以开采权证限定的矿物；</p><p>执行采矿许可证中的附属条款，促进当地商业发展；</p><p>执行采矿许可证中的附属条款，雇佣和培训赞比亚公民；</p><p>执行采矿许可证中的附属条款，进行预期额度投资；</p><p>对采矿区域进行划区，并按规定的方式保留划定的区块。</p><p>第(2)款：大规模采矿许可证持有人还应履行如下义务：</p><p>在其办公场所，对下述文件进行存档：</p><p>在采矿区域内进行采矿工作的全面的、准确的技术记录；</p><p>所有地图和地质报告的拷贝件，内容包括：地图说明、矿物分析、航测照片、钻孔日记、及持证人对取自采矿区域的矿物样本的分析和测试结果；</p><p>采矿区域相关的岩心钻孔；</p><p>矿区作业的准确的财务记录，和矿业司长可能要求的其它财务账本及财务记录；以及</p><p>由于持证人从事权证规定外的任何矿业活动所产生的单独的财务账本。</p><p>同意授权官员随时检查根据第(a)段所编制及存档的账本和记录，并无偿将矿业司长可能要求的部分账本或记录的拷贝件带走、递交给矿业司长；</p><p>以矿业部长可能要求的方式，保存关于环境保护的文档记录；</p><p>将矿业司长可能要求提供的矿区作业的报告、记录和其它材料递交给矿业司长；</p><p>在每个财政年度末尾的3个月内，将年度审计财务报表副本提交给矿业司长，以便矿业司长能够了解到持证人的项目年度收益或损失及其每个财政年度的年末财务状态。</p><p>第(3)款：大规模采矿许可证持有人如果：</p><p>没有保存任何按照本条第(2)款规定要求保存的记录或材料；</p><p>没有按照本条第(2)款规定向矿业司长提交任何记录文件；或者</p><p>提交了任何不真实的或具有误导性的记录或材料；</p><p>如上情形一经证实，即构成违规，需承担相应的责任，即交纳不超过K200,000.00的罚金或接受不超过2年的监禁或两罪并罚。</p><p><strong>31条</strong></p><p>第(1)款：大规模采矿许可证持有人对采矿规划书有任何的修改意向时，应按照指定的格式将修改申请提交给矿业司长。</p><p>第(2)款：矿业司长收到申请人根据本条第(1)款规定编制提交的修改申请后，有权：</p><p>批准修改申请（无论修改与否），且决定修改后的条款（如有）生效；或者</p><p>拒绝修改申请并向申请人阐明理由。</p><p><strong>32条</strong></p><p>第(1)款：大规模采矿许可证或任何相关权益，在未经矿业司长批准的前提下，不得以任何其它形式被转让、分配、延期或交易。</p><p>第(2)款：大规模采矿许可证持有人若有意将其权证按某种方式进行转让、分配、延期或交易，则应向矿业司长提交申请，并按要求提供权证受让人、被分配人、或其它相关机构在申请大规模采矿许可证时要求提供的详细资料。</p><p>第(3)款：根据本条第(2)款提交的申请若符合本法案规定，且大规模采矿许可证受让人具备本法案规定下的持证资格，矿业司长应批准持证人的权证或权益的转让、分配、延期或交易行为。</p><p>第(4)款：本条规定中的权力或其相关权益只能在权证的有效期限内被转让。</p><p>第(5)款：任何违反本法案规定的大规模采矿许可证转让行为均属无效。</p><p>第(6)款：本条规定中大规模采矿许可证里所提到的“权益”指的是持证人是公司法人性质下的控股权益。</p><p><strong>33条</strong></p><p>第(1)款：根据本条第(5)款的规定，持证人在行使其权证所赋予权利的过程中，探明了任何持证人未经许可去开采的，或任何不在其权证限定范围内的矿物，则持证人应在探明该矿物后的30天内，将勘探结果通知矿业司长，并提交包括矿物详情、矿物地点及矿物环境等细目的勘探报告。</p><p>第(2)款：大规模采矿许可证持有人在采矿前，应将其探明的任何权证限定范围内的矿物的开采申请、预定的采矿规划书提交给矿业司长以便获得开采批准。</p><p>第(3)款：根据本条第(2)款规定编制提交的采矿规划书若符合本法案的规定，则矿业司长应批准申请人的采矿申请，同时对大规模采矿许可证的条款进行修订。</p><p>第(4)款：除了矿业司长允许申请人按指定的方式修改规划书的情形之外，矿业司长不应拒绝申请人根据本条第(3)款规定编制提交的申请。</p><p>第(5)款：本条第(1)款规定涉及探明的矿物是宝石时，大规模采矿许可证持有人应根据本法案第36条规定申请大规模宝石许可证。</p><p>第(6)款：大规模采矿许可证持有人在探明石油后，应在探明后的24小时内，将勘探结果通知矿业司长。</p><p><strong>34条</strong></p><p>第(1)款：按照本法案的其它规定，大规模采矿许可证持有人可以根据如下任何原因而暂停或缩减采矿工作：</p><p>工作环境不安全；</p><p>由于采矿工作导致的不可控污染；</p><p>任何不可抗力；或者</p><p>任何扰乱采矿工作的劳动争议；</p><p>如有以上情形，大规模采矿许可证持有人应向矿业司长提交暂停采矿工作通知书并解释暂停原因。</p><p>第(2)款：大规模采矿许可证持有人提交通知书的具体情形：</p><p>持证人的权证尚未作废，或因为除了本条第(1)款(a)到(d)段所规定的其它原因，持证人应至少提前90天将暂停采矿通知书提交给矿业司长；以及</p><p>至少提前30天，将缩减采矿工作通知书提交给矿业司长；</p><p>若满足以上任意情形之一，持证人需对暂停或缩减采矿工作的原因做出解释。</p><p>第(3)款： 收到持证人根据本条第(1)款规定所递交的通知书后，并意识到采矿工作的暂停或缩减，则矿业司长可以对暂停或缩减原因进行调查，以及可以：</p><p>在其职权范围内批准大型采矿许可证的延期、采矿工作的暂停或缩减；或者</p><p>指令持证人在限定的期限内全面恢复采矿工作。</p><p>第(4)款：在本条第(1)款(c)段中的“不可抗力”指的是超出持证人合理可控范围之外的，以及迫使权证规定的采矿活动在特定情形下无法进行的事件。</p><p><strong>35条</strong></p><p>第(1)款：持证人在其权证到期前的不晚于1年的任何时间内，可就其权证圈定下的全部或部分采矿区域，向矿业司长提交更新申请。</p><p>第(2)款：更新申请需以指定的格式编制提交，并交纳规定的申请费用。</p><p>第(3)款：根据本条第(2)款规定编制提交的更新申请中应包含：</p><p>一份期限说明，即更新后的权证有效期不得超过25年；</p><p>如下细目：</p><p>最新探明的、预期的、预想的矿石、矿物；</p><p>投资额度、相关的开采成本和收益预测，及更新后的有效期限；</p><p>针对矿物开采和处理方法的任何修改；</p><p>任何采矿工作的增加或减少，及矿物的预估开采年限；</p><p>更新后的有效期限内的采矿计划书；以及</p><p>一份采矿区域甄别计划书（适用于只是对部分采矿区域提交更新申请的情形）</p><p>第(4)款：根据本条第(6)款的规定，若大规模采矿许可证更新申请符合本法案的要求，则矿业司长应批准更新，且更新后的权证有效期限不得超过25年。</p><p>第(5)款：矿业司长在对大规模采矿许可证进行更新时，可选择是否对权证内的条款进行更改。</p><p>第(6)款：若满足以下情形，矿业司长可拒绝大规模采矿许可证的更新申请：</p><p>矿区开采工作进度缓慢；</p><p>可加工型矿物储量不够被开采；</p><p>预期采矿工作规划不能保障矿区的矿物资源在国家利益上的合理保存和使用；或者</p><p>申请人违反了其持有的权证或本法案的任何规定。</p><p>第(7)款：矿业司长不能以任何理由拒绝处于下列情形的大规模采矿许可证更新申请：</p><p>本条第(6)款(a)段中所列情形，除非矿业司长已通知申请人其违约细目，但申请人在通知到达后的3个月内依然不对违约行为进行弥补；</p><p>本条第(6)款(b)段中所列情形，除非矿业司长允许申请人起草一份书面解释函并提交给矿业司长；或者</p><p>本条第(6)款(c)段中所列情形，除非矿业司长已通知申请人其采矿工作规划缺陷，而申请人在通知到达后的3个月内依然不对其采矿工作规划缺陷进行弥补。</p><p>第(8)款：根据本法案的其它规定，大规模采矿许可证更新后的有效期限不得超过25年，在此25年的有效期限内，持证人需展开积极合理的采矿工作。</p><p>第(9)款：大规模采矿许可证更新后，矿业司长可在其权证上附加一份已批准通过的采矿规划书，用于指导权证更新后的有效期限内开展采矿工作。</p><p>第三章 大规模宝石许可证</p><p><strong>36条-46条</strong></p><p>类似金属矿证。</p><p><strong>第四部分</strong></p><p>小规模采矿作业</p><p>第一章 探矿特许证</p><p><strong>47条</strong></p><p>第(1)款：探矿特许证申请人应按指定的格式填写申请，交纳规定的申请费用，并将申请递交至地质测量司司长处。</p><p>第(2)款：根据本条第(1)款规定编制递交的申请，应包含如下材料：</p><p>一份除宝石之外的拟进行勘探的矿物说明；</p><p>使用地理坐标对申请的地块进行描述和草绘，此地块不应在面积上大于300个地籍单位（完整的地籍单位，且该面积足以进行探矿区域划定），并提交一份附属于探矿特许证的探矿计划书；</p><p>一份申请人的环境管理方案，包括：防止污染预案、尾矿处理方案、土地及水利资源保护及再生方案，以及能够防止或最小化探矿作业对环境所产生的负面影响的方案；</p><p>一份申请人拟定的探矿费用说明；</p><p>一份任何申请人已获取的采矿权说明，或任何之前申请人所申请的采矿权说明；</p><p>一份依据《所得税法》出具的完税证明。</p><p><strong>48条</strong></p><p>第(1)款：地质测量司司长在审核按照本法案第47条规定编制提交的申请时，应考虑申请人是否具备以下条件：</p><p>申请人具有或能够获得充足的资金来源、雄厚的技术实力和丰富的矿业经验，以便有效地展开探矿工作；</p><p>申请人具有详尽的探矿规划书，以及妥善的环境保护方案；</p><p>申请人已提交了要求提交的进场同意函证明，以进入任何书面法律规定持函进场的地块；</p><p>涉及到探矿区域、或采矿区域、或部分探矿、采矿区域，申请人已获得该类区域的探矿许可证或其它许可证持有人的探矿批准，且该类持证人的利益不会因为授权探矿而造成损害。</p><p>第(2)款：在有必要对申请人进行审核以评定其是否满足本条第(1)款规定时，地质测量司司长可执行相关的调查与咨询工作。</p><p>第(3)款：针对下列情形，地质测量司司长应拒绝探矿特许证申请：</p><p>因本法案第7条规定，申请人不具备持有探矿特许证的资格；</p><p>申请人所申请的探矿特许证，其限定区域已被采矿权所圈定；或</p><p>申请人违反了任何本法案或其它采矿权的规定。</p><p>第(4)款：因本条第(3)款规定，地质测量司司长拒绝探矿特许证申请，则应将受理结果通知申请人并阐述相关理由。</p><p><strong>49条</strong></p><p>第(1)款：根据本法案第47条规定编制递交的申请符合本法案要求时，地质测量司司长应在收到申请后的30天内，将探矿特许证授予申请人。</p><p>第(2)款：探矿特许证应：</p><p>注明签证日期、权限和条款；</p><p>注明权证限定的矿物；以及</p><p>包含探矿区域的描述与计划。</p><p>第(3)款：由地质测量司司长批准的探矿规划书，应附在探矿特许证中且被视为探矿特许证的部分条款。</p><p>第(4)款：探矿特许证限定区域不得超过300个地籍单位。</p><p><strong>50条</strong></p><p>探矿特许证有效期限不得超过5年，且不可以更新。</p><p><strong>51条</strong></p><p>第(1)款：探矿特许证持有人可根据其权证所赋予的权利，在探矿区域内对除了宝石之外的权证中列明的矿物进行勘探或其它有必要的、相关的矿业活动。</p><p>第(2)款：探矿特许证或任何相关权益，在未经地质测量司司长批准的前提下，不得以任何其它形式被转让、分配、延期或交易。</p><p>第(3)款：持证人若有意将其权证按某种方式进行转让、分配、延期或交易，则应向地质测量司司长提交申请，并按要求提供申请探矿特许证时要求被提供的权证受让人、被分配人、或其它相关机构的详细资料。</p><p>第(4)款：根据本条第(3)款规定编制提交的申请若符合本法案规定，且权证受让人具备本法案规定下的持证资格，地质测量司司长应在探矿特许证的有效期限内，批准其权证或权益的转让、分配、延期或交易行为。</p><p>第(5)款：任何违反本法案规定的探矿特许证转让的交易行为均属无效。</p><p>第(6)款：本条中探矿特许证里所提到的“权益”指的是持证人是公司法人性质下的控股权益。</p><p><strong>52条</strong></p><p>探矿特许证持有人应：</p><p>在探矿区域内探明任何具有商业价值的矿物后，于探明后的30天内将结果通知到地方矿业办公室；</p><p>在其办公场所内对探矿作业进行完整的、准确的记录，内容包含：</p><p>钻孔；</p><p>穿透的岩层及岩层详细日志；</p><p>探明的矿物；</p><p>任何地震学勘测或地球化学、地球物理和远程传感数据分析结果；</p><p>任何矿物分析或鉴定结果；</p><p>本条第(i)到(v)段中包含的记录的地质说明；</p><p>雇员数量；</p><p>探矿特许证涉及到的其它工作；</p><p>探矿费用；以及</p><p>矿业部长根据法令规定的其它事宜；以及</p><p>按矿业部长根据法令制定的要求，将关于环境保护的工作记录保存一定的时期。</p><p><strong>53 条</strong></p><p>第(1)款：除了对矿物进行实验、分析的用途外，在未经取得当地矿业办公室授权官员的书面批准的前提下，持证人不得从探矿区域带走任何矿物，取得书面批准后，应按照授权官员在批准中的规定要求，从探矿区取走任何矿物。</p><p>第(2)款：从探矿区域取走的用于分析或实验的矿物样本，其数量由矿业部长根据法律条文确定。</p><p>第二章 小规模采矿许可证</p><p><strong>54条</strong></p><p>第(1)款：探矿特许证持有人在权证的有效期限内，可针对探矿区域的任何地块，以规定的方式向矿业司长提交小规模采矿许可证申请，并交纳规定的申请费用。</p><p>第(2)款：根据本条第(1)款规定编制递交的申请，应包含：</p><p>一份相关的探矿特许证的证明材料；</p><p>使用地理坐标对申请的地块进行描述和草绘，此地块不应在面积上大于120个地籍单位，且该面积足以进行探矿区域划定；</p><p>一份采矿规划书，内容包括投资额度预期、矿石及其它矿产品的预计回收率、以及针对回收的矿石及矿产品所制定的计划处理方案；</p><p>一份根据申请人的经验对所申请地块中的矿床的说明；</p><p>一份所申请的小规模采矿许可证有效期限不超过10年的说明；</p><p>一份依据“所得税法”出具的完税证明；</p><p>矿业司长在受理申请时可能要求的其它资料。</p><p><strong>55条</strong></p><p>第(1)款：在审核根据本法案第54条规定编制提交的申请时，矿业司长应考虑申请人是否具备以下条件：</p><p>申请人是否有或能够获得充足的资金来源、雄厚的技术实力和丰富的采矿经验，以便进行有效的小规模采矿作业；</p><p>申请人是否制定了完善的小规模采矿规划书及适当的环保方案；</p><p>申请人已提交了要求提交的进场同意函证明，以进入任何书面法律规定持函进场的地块；</p><p>第(2)款：在有必要对申请人进行审核以评定其是否满足本条第(1)款规定时，地质测量司司长可执行相关的调查与咨询工作。</p><p>第(3)款：申请人处于下列情形时，矿业司长可拒绝其小规模采矿许可证申请：</p><p>根据本法案第62条规定，申请人已被要求申请大规模采矿许可证；</p><p>根据本法案第7条规定，申请人不具备持证资格；</p><p>所申请的小规模采矿许可证的限定区域大于申请人所探明矿物的开采区域；或者</p><p>申请人违反了本法案或其它采矿权的任何规定。</p><p>第(4)款：因本条第(3)款规定，矿业司长拒绝小规模采矿许可证申请，则应将受理结果通知申请人并阐述相关理由。</p><p><strong>56条</strong></p><p>第(1)款：根据本法案第54条规定编制递交的申请符合本法案要求时，矿业司长应在收到申请后的30天内，将小规模采矿许可证授予申请人。</p><p>第(2)款：小规模采矿许可证应：</p><p>注明签证日期、权限和条款；</p><p>注明权证限定的矿物；以及</p><p>包含采矿区域的描述与计划。</p><p>第(3)款：由矿业司长批准的采矿规划书，应附在小规模采矿许可证中且被视为小规模采矿许可证的部分条款。</p><p>第(4)款：小规模采矿许可证限定区域不得超过120个地籍单位。</p><p><strong>57条</strong></p><p>小规模采矿许可证有效期限不得超过10年。</p><p><strong>58条</strong></p><p>第(1)款：小规模采矿许可证持有人可根据其权证所赋予的权利，在采矿区域内对除了宝石之外的权证中列明的矿物进行开采或其它有必要的、相关的矿业活动。</p><p>第(2)款：除了本条第(1)款的一般规定外，小规模采矿许可证持有人还可行使如下权利：</p><p>进入采矿区域，进行以采矿为目的的所有合理的地表或地下矿业工作；</p><p>装配必要的设备、工厂和建筑物，用于在采矿过程中所探明矿物的开采、运输、加工或处理；</p><p>对任何探明的矿物进行处理；</p><p>在采矿区域内对任何矿物进行勘探；以及</p><p>堆积或倾倒任何废矿或废品。</p><p><strong>59条</strong></p><p>第(1)款：小规模采矿许可证持有人应履行如下义务：</p><p>遵从采矿规划书规定，积极开发采矿区域，进行采矿工作；</p><p>以规定的方式对采矿区域进行区域划定，并保留划定的区域；</p><p>在其办公场所，对下述文件进行存档：</p><p>按矿业司长允许的格式对采矿区域内的采矿作业的全面的、准确的技术记录；</p><p>所有地图和地质报告的拷贝件，内容包括：地图说明、矿物分析、航测照片、钻孔日记、及持证人对取自采矿区域的矿物样本的分析和测试结果；</p><p>采矿工作产生的准确的、系统的财务记录，和矿业司长可能要求的其它财务账本及财务记录；以及</p><p>由于持证人从事其权证限定外的任何矿业活动所产生的单独的财务账本。</p><p>同意授权官员随时检查根据本条第(a)段所编制及存档的账本和记录，并无偿将矿业司长可能要求的部分账本或记录的拷贝件带走、递交给矿业司长；</p><p>以矿业部长可能要求的方式，保存关于环境保护的文档记录；</p><p>在每个财政年度末尾的3个月内，将年度审计财务报表副本提交给矿业司长，以便矿业司长能够了解到持证人的项目年度收益或损失及其每个财政年度的年末财务状态。</p><p>将矿业司长可能要求提供的矿区采矿作业的报告、记录和其它材料递交给矿业司长。</p><p>第(2)款：持证人如果：</p><p>没有保存任何按照本条第(1)款规定要求保存的记录或材料；</p><p>没有按照本条第(1)款规定向矿业司长提交任何记录文件；或者</p><p>提交了任何不真实的或具有误导性的记录或材料；</p><p>如上情形一经正式，即构成违规，需承担相应的责任，即交纳不超过K200,000.00的罚金或接受不超过2年的监禁或两罪并罚。</p><p><strong>60条</strong></p><p>第(1)款：在小规模采矿许可证到期前的至少60天内，持证人可以规定的方式向矿业司长提交权证更新申请，并交纳相应的申请费用。</p><p>第(2)款：根据本条第(3)款规定，小规模采矿许可证更新申请符合本法案的要求时，矿业司长应将其权证进行更新，更新后的有效期限不得超过10年。</p><p>第(3)款：持证人处于下列情形时，矿业司长可拒绝其权证更新申请：</p><p>矿区开采工作进度缓慢；</p><p>可加工型矿物储量不够被开采；</p><p>拟定的采矿作业规划不能保障矿区的矿产资源在国家利益上的合理保存和使用；或者</p><p>申请人违反了其权证或本法案的任何规定。</p><p>第(4)款：矿业司长不能以任何理由拒绝处于下列情形的小规模采矿许可证更新申请：</p><p>本条第(3)款(a)段中所列情形，除非矿业司长已通知申请人其违约细目，而申请人在通知到达后的3个月内依然不对违约行为进行弥补；</p><p>本条第(3)款(b)段中所列情形，除非矿业司长允许申请人起草一份书面解释函并提交给矿业司长；或者</p><p>本条第(3)款(c)段中所列情形，除非矿业司长已通知申请人其采矿作业规划缺陷，而申请人在通知到达后的3个月内依然不对其该缺陷进行弥补。</p><p>第(5)款：小规模采矿许可证更新后有效期限内的采矿规划书，经批准后，矿业司长应将其附在更新后的权证中。</p><p><strong>61条</strong></p><p>第(1)款：小规模采矿许可证或任何相关权益，在未经矿业司长批准的前提下，不得以任何其它形式被转让、分配、延期或交易。</p><p>第(2)款：小规模采矿许可证持有人若有意将其权证按某种方式进行转让、分配、延期或交易，则应向矿业司长提交申请，并按要求提供在申请小规模采矿许可证时要求被提供的权证受让人、被分配人、或其它相关机构的详细资料。</p><p>第(3)款：上述申请若符合本法案规定，且小规模采矿许可证受让人具备本法案规定下的持证资格，矿业司长应在小规模采矿许可证有效期限内，批准其权证或权益的转让、分配、延期或交易行为。</p><p>第(4)款：本条中小规模采矿许可证里所提到的“权益”指的是持证人是公司法人性质下的控股权益。</p><p>第(5)款：任何违反本法案规定的小规模采矿许可证转让的交易行为均属无效。</p><p><strong>62条</strong></p><p>第(1)款：矿业司长可要求：</p><p>小规模采矿许可证申请人；或</p><p>矿业司长有合理的理由认定的正在从事大型采矿工作的原小规模采矿许可证持有人；</p><p>去申请大规模采矿许可证。</p><p>第(2)款：因本条第(1)款规定而申请大规模采矿许可证的小规模采矿许可证申请人或正在从事大型采矿工作的原小规模采矿许可证持有人，应被视为和申请大规模采矿许可证的探矿许可证持有人一样，均需遵从本法案的规定。</p><p><strong>63条</strong></p><p>连续3年或更长时间以上，小规模采矿许可证持有人未根据其采矿规划书的规定去执行相应的采矿工作，及超过连续3年或更长时间后，持证人每年的矿石开采量少于预期回采率的50%，矿业司长应取缔持证人的权证。</p><p>第三章 小规模宝石许可证</p><p><strong>64-73条</strong></p><p>类似金属矿证</p></div>',2)])])}const l=t(r,[["render",g]]);export{_ as __pageData,l as default};
